#include <Wire.h>
#include <Adafruit_SSD1306.h>

extern int pid_heater_control(float sp,float pv,float dt,float kp,float ki,float kd,float* intg,float* lastE);
extern int sma_hysteresis_pid(float sp,float pv,float dt,float wire_temp,float* intg,float* lastE);

Adafruit_SSD1306 oled(128,32,&Wire,-1);
const int SMA_PIN=9,POT_PIN=A0,NTC_PIN=A1;
const float R_NTC=10000.0f,B_NTC=3950.0f;
float intg=0,lastE=0;
float sp_mm=20.0f;

// === Potentiometer ===
void pot_init(){pinMode(POT_PIN,INPUT);}
float pot_read(){float s=0;for(int i=0;i<10;i++)s+=analogRead(POT_PIN);return s/10.0f*50.0f/1023.0f;}

// === NTC Wire Temp ===
void ntc_init(){pinMode(NTC_PIN,INPUT);}
float ntc_read(){float v=analogRead(NTC_PIN)*3.3f/1023.0f;float r=R_NTC*v/(3.3f-v);return 1.0f/(1.0f/298.15f+(1.0f/B_NTC)*log(r/R_NTC))-273.15f;}

// === SMA Driver ===
void sma_init(){pinMode(SMA_PIN,OUTPUT);analogWrite(SMA_PIN,0);}
void sma_set(int p){analogWrite(SMA_PIN,constrain(p,0,255));}

// === OLED Display ===
void display_update(float sp,float pv,float wt,int pwm,bool fault){
  oled.clearDisplay();oled.setTextSize(1);oled.setTextColor(SSD1306_WHITE);
  oled.setCursor(0,0);oled.print("SP:");oled.print(sp,1);oled.print(" PV:");oled.print(pv,1);oled.println("mm");
  oled.setCursor(0,12);if(fault){oled.print("!! FAULT OVERTEMP");}else{oled.print("Tw:");oled.print(wt,0);oled.print("C D:");oled.print(pwm*100/255);oled.print("%");}
  oled.display();}

// === Fault Handler ===
bool fault_check(float wt){if(wt>130.0f){sma_set(0);Serial.println("FAULT:WIRE_HOT");return true;}return false;}

void setup(){
  Serial.begin(115200);Wire.begin();
  pot_init();ntc_init();sma_init();
  oled.begin(SSD1306_SWITCHCAPVCC,0x3C);oled.clearDisplay();oled.display();
  Serial.println("t_ms,sp,pv,wire_C,pwm");
}

unsigned long lastMs=0;
void loop(){
  unsigned long now=millis();
  float dt=(now-lastMs)/1000.0f;
  if(dt<0.1f)return;lastMs=now;
  float pv=pot_read(),wt=ntc_read();
  bool fault=fault_check(wt);
  int pwm=0;
  if(!fault)pwm=sma_hysteresis_pid(sp_mm,pv,dt,wt,&intg,&lastE);
  sma_set(pwm);
  display_update(sp_mm,pv,wt,pwm,fault);
  Serial.print(now);Serial.print(',');Serial.print(sp_mm,1);Serial.print(',');Serial.print(pv,2);Serial.print(',');Serial.print(wt,1);Serial.print(',');Serial.println(pwm);
}
